              <span className="text-xs font-semibold text-amber-700 uppercase tracking-widest bg-amber-200 px-2 py-1 rounded">
                Round {maxRounds + 1}
              </span>
            </div>
            <div className="p-6">
              <div className="flex flex-col items-center mb-6">
                <p className="text-4xl font-bold text-stone-900 scrabble-font text-center">
                  {players[currentPlayerIndex]?.name}
                </p>
                <button 
