              <div className="flex flex-col items-center mb-6 min-h-[100px] justify-center">
                {editingPlayerId === currentPlayer.id ? (
                  <div className="w-full flex flex-col items-center gap-3 animate-in fade-in zoom-in duration-200">
                    <input
                      autoFocus
                      type="text"
                      value={editNameValue}
                      onChange={(e) => setEditNameValue(e.target.value)}
                      onKeyDown={(e) => {
                        if (e.key === 'Enter') savePlayerName();
                        if (e.key === 'Escape') cancelEditingName();
                      }}
                      className="w-full bg-stone-50 border-2 border-amber-400 rounded-xl px-4 py-2 text-2xl font-bold text-center text-stone-900 focus:ring-4 focus:ring-amber-100 outline-none transition-all"
                    />
                    <div className="flex gap-4">
                      <button 
                        onClick={savePlayerName} 
                        className="flex items-center gap-2 px-4 py-2 bg-green-600 text-white rounded-lg font-bold hover:bg-green-700 shadow-md transition-all active:scale-95"
                      >
                        <Check size={18} /> Save
                      </button>
                      <button 
                        onClick={cancelEditingName} 
                        className="flex items-center gap-2 px-4 py-2 bg-stone-200 text-stone-600 rounded-lg font-bold hover:bg-stone-300 transition-all active:scale-95"
                      >
                        <X size={18} /> Cancel
                      </button>
                    </div>
                  </div>
                ) : (
                  <>
                    <p className="text-4xl font-bold text-stone-900 scrabble-font text-center">
                      {currentPlayer?.name}
                    </p>
                    <button 
                      onClick={() => startEditingName(currentPlayer)}
                      className="mt-2 text-stone-400 hover:text-amber-600 flex items-center gap-1 text-sm font-medium transition-colors"
                    >
                      <Pencil size={14} />
                      Edit Name
                    </button>
                  </>
                )}
              </div>

              <div className="space-y-4">
                <div className="space-y-1">
                  <label className="text-xs font-bold text-stone-500 uppercase tracking-wider">Played Word</label>
                  <input
                    type="text"
                    value={wordInput}
                    onChange={(e) => setWordInput(e.target.value.toUpperCase())}
                    onKeyDown={(e) => e.key === 'Enter' && submitTurn()}
                    placeholder="ENTER WORD..."
                    className="w-full bg-stone-50 border-2 border-stone-200 rounded-xl px-4 py-3 text-lg font-bold tracking-widest focus:ring-2 focus:ring-amber-500 focus:border-transparent transition-all outline-none"
                  />
                </div>

                <div className="space-y-1">
                  <label className="text-xs font-bold text-stone-500 uppercase tracking-wider">Points</label>
                  <input
                    type="number"
                    value={pointsInput}
                    onChange={(e) => setPointsInput(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && submitTurn()}
                    placeholder="Points"
                    className="w-full bg-stone-50 border-2 border-stone-200 rounded-xl px-4 py-3 text-xl font-bold focus:ring-2 focus:ring-amber-500 focus:border-transparent transition-all outline-none"
                  />
                </div>

                <div className="flex flex-col gap-3 pt-2">
                  <button
                    onClick={submitTurn}
                    disabled={!wordInput || !pointsInput}
                    className="w-full bg-amber-600 hover:bg-amber-500 disabled:bg-stone-200 disabled:text-stone-400 text-white py-4 rounded-xl font-bold text-lg shadow-lg hover:shadow-amber-200/50 transition-all flex items-center justify-center gap-2"
                  >
                    <Send size={20} />
                    Play Word
                  </button>

                  <button
                    onClick={nextTurn}
                    className="w-full bg-stone-800 hover:bg-stone-700 text-stone-200 py-4 rounded-xl font-bold text-lg transition-all flex items-center justify-center gap-2 shadow-lg"
                  >
                    <SkipForward size={20} />
                    End Turn
                  </button>
                </div>
              </div>

              {/* AI Insight */}
              {(definition || isLoadingDef) && (
                <div className="mt-6 p-4 bg-stone-50 rounded-xl border border-stone-100 flex gap-3 animate-in fade-in duration-300">
                  <Info className="text-amber-600 shrink-0" size={18} />
                  <div>
                    <h4 className="text-xs font-bold text-stone-400 uppercase tracking-wider mb-1">AI Insight</h4>
                    {isLoadingDef ? (
                      <div className="flex gap-1">
                        <div className="w-1.5 h-1.5 bg-stone-300 rounded-full animate-bounce"></div>
                        <div className="w-1.5 h-1.5 bg-stone-300 rounded-full animate-bounce delay-75"></div>
                        <div className="w-1.5 h-1.5 bg-stone-300 rounded-full animate-bounce delay-150"></div>
                      </div>
                    ) : (
                      <p className="text-sm text-stone-600 italic">"{definition}"</p>
                    )}
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* Player Quick Stats */}
          <div className="space-y-3">
            <h2 className="text-xs font-bold text-stone-500 uppercase tracking-widest px-1">Leaderboard</h2>
            {players.map((p, idx) => (
              <StatsCard
                key={p.id}
                name={p.name}
                stats={getPlayerStats(p)}
                isActive={idx === currentPlayerIndex}
              />
            ))}
          </div>
        </div>

        {/* Right Column: Score Table */}
        <div className="lg:col-span-8 bg-white rounded-2xl shadow-sm border border-stone-200 overflow-hidden flex flex-col">
          <div className="bg-stone-50 p-4 border-b border-stone-200 flex justify-between items-center">
            <h2 className="font-bold text-stone-800">Score Sheet</h2>
            <div className="flex gap-2">
               <span className="w-3 h-3 rounded-full bg-red-400"></span>
               <span className="w-3 h-3 rounded-full bg-amber-400"></span>
               <span className="w-3 h-3 rounded-full bg-green-400"></span>
            </div>
          </div>

          <div className="overflow-x-auto flex-grow">
            <table className="w-full text-left border-collapse min-w-[600px]">
              <thead>
                <tr className="bg-stone-50 border-b border-stone-200">
                  <th className="px-6 py-4 text-xs font-bold text-stone-400 uppercase tracking-widest w-16">Entry</th>
                  {players.map((p, idx) => (
                    <th key={p.id} className={`px-6 py-4 relative group ${idx === currentPlayerIndex ? 'bg-amber-50/50' : ''}`}>
                      <div className="flex items-center justify-between gap-2">
                        <div className="flex items-center gap-2 overflow-hidden">
                          <span className={`font-bold truncate ${idx === currentPlayerIndex ? 'text-amber-700' : 'text-stone-800'}`}>
                            {p.name}
                          </span>
                          {!isGameStarted && (
                            <button 
                              onClick={() => startEditingName(p)}
                              title="Edit name"
                              className="text-stone-300 hover:text-amber-500 transition-colors opacity-0 group-hover:opacity-100"
                            >
                              <Pencil size={14} />
                            </button>
                          )}
                        </div>
                        {!isGameStarted && players.length > 1 && (
                          <button 
                            onClick={() => removePlayer(p.id)}
                            title="Remove player"
                            className="text-stone-300 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100 shrink-0"
                          >
                            <X size={16} />
                          </button>
                        )}
                      </div>
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody className="divide-y divide-stone-100">
                {Array.from({ length: maxEntries }).map((_, entryIdx) => (
                  <tr key={entryIdx} className="hover:bg-stone-50/50 transition-colors">
                    <td className="px-6 py-3 text-sm font-bold text-stone-400">{entryIdx + 1}</td>
                    {players.map((p, playerIdx) => (
                      <td key={p.id} className={`px-6 py-3 ${playerIdx === currentPlayerIndex ? 'bg-amber-50/20' : ''}`}>
                        {p.turns[entryIdx] ? (
                          <div className="flex items-center justify-between">
                            <span className="font-medium text-stone-700 tracking-wide">{p.turns[entryIdx].word}</span>
                            <span className="text-sm font-bold bg-stone-100 px-2 py-0.5 rounded text-stone-600">
                              {p.turns[entryIdx].points}
                            </span>
                          </div>
                        ) : (
                          <span className="text-stone-200">—</span>
                        )}
                      </td>
                    ))}
                  </tr>
                ))}

                {maxEntries === 0 && (
                  <tr>
                    <td colSpan={players.length + 1} className="px-6 py-12 text-center text-stone-400 italic">
                      No words played yet. Start by entering a word for {players[currentPlayerIndex].name}.
                    </td>
                  </tr>
                )}
              </tbody>
              <tfoot className="sticky bottom-0 bg-stone-900 text-white font-bold border-t-4 border-amber-600 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.1)]">
                <tr>
                  <td className="px-6 py-6 text-xs uppercase tracking-widest text-stone-400">Total</td>
                  {players.map((p) => (
                    <td key={p.id} className="px-6 py-6 text-2xl scrabble-font">
                      {p.turns.reduce((sum, t) => sum + t.points, 0)}
                    </td>
                  ))}
                </tr>
              </tfoot>
            </table>
          </div>
        </div>
      </main>

      {/* Footer Mobile Stats Toggle */}
      <div className="fixed bottom-4 right-4 lg:hidden">
        <button className="bg-stone-900 text-white p-4 rounded-full shadow-2xl border border-stone-700 flex items-center justify-center">
          <Trophy size={24} />
        </button>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo, useEffect } from 'react';
import { Plus, RotateCcw, Send, SkipForward, Info, Trophy, Users, Pencil, Check, X, UserPlus } from 'lucide-react';
import { Player, Turn, PlayerStats } from './types';
import StatsCard from './components/StatsCard';
import { defineWord } from './services/geminiService';

const App: React.FC = () => {
  const [players, setPlayers] = useState<Player[]>([
    { id: '1', name: 'Player 1', turns: [] },
    { id: '2', name: 'Player 2', turns: [] }
  ]);
  const [currentPlayerIndex, setCurrentPlayerIndex] = useState(0);
  const [gameRound, setGameRound] = useState(1);
  const [wordInput, setWordInput] = useState('');
  const [pointsInput, setPointsInput] = useState('');
  const [definition, setDefinition] = useState<string | null>(null);
  const [isLoadingDef, setIsLoadingDef] = useState(false);

  // Name Editing State
  const [editingPlayerId, setEditingPlayerId] = useState<string | null>(null);
  const [editNameValue, setEditNameValue] = useState('');

  const isGameStarted = useMemo(() => 
    players.some(p => p.turns.length > 0),
  [players]);

  const startNewGame = useCallback(() => {
    if (confirm("Reset current game and scores?")) {
      setPlayers(prev => prev.map(p => ({ ...p, turns: [] })));
      setCurrentPlayerIndex(0);
      setGameRound(1);
      setWordInput('');
      setPointsInput('');
      setDefinition(null);
      setEditingPlayerId(null);
    }
  }, []);

  const addPlayer = useCallback(() => {
    if (isGameStarted) return;
    const newId = Math.random().toString(36).substr(2, 9);
    setPlayers(prev => [...prev, { id: newId, name: `Player ${prev.length + 1}`, turns: [] }]);
  }, [players.length, isGameStarted]);

  const removePlayer = useCallback((id: string) => {
    if (isGameStarted || players.length <= 1) return;
    setPlayers(prev => prev.filter(p => p.id !== id));
    setCurrentPlayerIndex(0);
  }, [isGameStarted, players.length]);

  const startEditingName = (player: Player) => {
    setEditingPlayerId(player.id);
    setEditNameValue(player.name);
  };

  const savePlayerName = () => {
    if (!editNameValue.trim() || !editingPlayerId) {
      setEditingPlayerId(null);
      return;
    }
    setPlayers(prev => prev.map(p => 
      p.id === editingPlayerId ? { ...p, name: editNameValue.trim() } : p
    ));
    setEditingPlayerId(null);
  };

  const cancelEditingName = () => {
    setEditingPlayerId(null);
  };

  // Aggregates words into the current round for the current player
  const submitWord = useCallback(() => {
    const points = parseInt(pointsInput);
    if (!wordInput.trim() || isNaN(points)) return;

    const roundIdx = gameRound - 1;

    setPlayers(prev => {
      const updated = [...prev];
      const player = { ...updated[currentPlayerIndex] };
      const newTurns = [...player.turns];

      if (newTurns[roundIdx]) {
        // Append to existing turn in this round
        newTurns[roundIdx] = {
          ...newTurns[roundIdx],
          word: `${newTurns[roundIdx].word}, ${wordInput.trim().toUpperCase()}`,
          points: newTurns[roundIdx].points + points,
        };
      } else {
        // First word for this player in this round
        newTurns[roundIdx] = {
          word: wordInput.trim().toUpperCase(),
          points,
          timestamp: Date.now()
        };
      }

      player.turns = newTurns;
      updated[currentPlayerIndex] = player;
      return updated;
    });

    setWordInput('');
    setPointsInput('');
    setDefinition(null);
  }, [wordInput, pointsInput, currentPlayerIndex, gameRound]);

  const endTurn = useCallback(() => {
    const roundIdx = gameRound - 1;

    // If the player hasn't played any words this round, we record a skip entry to keep table aligned
    setPlayers(prev => {
      if (prev[currentPlayerIndex].turns[roundIdx]) return prev;

      const updated = [...prev];
      const player = { ...updated[currentPlayerIndex] };
      const newTurns = [...player.turns];
      newTurns[roundIdx] = { word: '—', points: 0, timestamp: Date.now() };
      player.turns = newTurns;
      updated[currentPlayerIndex] = player;
      return updated;
    });

    // Advance round if it's the last player
    if (currentPlayerIndex === players.length - 1) {
      setGameRound(prev => prev + 1);
    }

    setCurrentPlayerIndex(prev => (prev + 1) % players.length);
    setWordInput('');
    setPointsInput('');
    setDefinition(null);
    setEditingPlayerId(null);
  }, [players.length, currentPlayerIndex, gameRound]);

  const getPlayerStats = useCallback((player: Player): PlayerStats => {
    const totalScore = player.turns.reduce((sum, t) => sum + (t?.points || 0), 0);
    const validTurns = player.turns.filter(t => t && t.word !== '—');
    const wordCount = validTurns.length;
    const averagePoints = wordCount > 0 ? totalScore / wordCount : 0;

    // Find highest individual score (since turns are aggregated, this technically finds highest round)
    const highestRound = player.turns.length > 0 
      ? [...player.turns].filter(t => t).sort((a, b) => b.points - a.points)[0]
      : null;

    return { 
      totalScore, 
      averagePoints, 
      highestWord: highestRound && highestRound.word !== '—' ? highestRound : null, 
      wordCount 
    };
  }, []);

  useEffect(() => {
    const timer = setTimeout(async () => {
      if (wordInput.length >= 3) {
        setIsLoadingDef(true);
        const def = await defineWord(wordInput);
        setDefinition(def);
        setIsLoadingDef(false);
      } else {
        setDefinition(null);
      }
    }, 800);
    return () => clearTimeout(timer);
  }, [wordInput]);

  const currentPlayer = players[currentPlayerIndex];

  return (
    <div className="min-h-screen bg-stone-100 pb-12">
      {/* Header */}
      <header className="bg-stone-900 text-white shadow-xl py-6 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 flex flex-wrap justify-between items-center gap-4">
          <div className="flex items-center gap-3">
            <div className="bg-amber-500 p-2 rounded-lg shadow-inner">
              <Trophy className="text-stone-900" size={24} />
            </div>
            <h1 className="text-2xl font-bold tracking-tight scrabble-font">LexiScore</h1>
          </div>

          <div className="flex items-center gap-3">
            <button
              onClick={startNewGame}
              className="flex items-center gap-2 bg-stone-800 hover:bg-stone-700 text-stone-300 px-4 py-2 rounded-lg transition-all border border-stone-700"
            >
              <RotateCcw size={18} />
              <span className="hidden sm:inline">Reset Game</span>
            </button>
            <button
              disabled={isGameStarted}
              onClick={addPlayer}
              className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-all ${
                isGameStarted 
                ? 'bg-stone-800 text-stone-600 cursor-not-allowed opacity-50' 
                : 'bg-amber-600 hover:bg-amber-500 text-white shadow-lg'
              }`}
            >
              <UserPlus size={18} />
              <span className="hidden sm:inline">Add Player</span>
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 mt-8 grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* Left Column: Input & Stats */}
        <div className="lg:col-span-4 space-y-6">
          {/* Active Player Status */}
          <div className="bg-white rounded-2xl shadow-sm border border-stone-200 overflow-hidden">
            <div className="bg-amber-50 p-4 border-b border-amber-100 flex items-center justify-between">
              <h2 className="font-bold text-stone-800 flex items-center gap-2">
                <Users size={18} className="text-amber-600" />
                Current Turn
              </h2>
              <span className="text-xs font-semibold text-amber-700 uppercase tracking-widest bg-amber-200 px-2 py-1 rounded">
                Round {gameRound}
              </span>
            </div>
            <div className="p-6">
              <div className="flex flex-col items-center mb-6 min-h-[100px] justify-center">
                {editingPlayerId === currentPlayer.id ? (
                  <div className="w-full flex flex-col items-center gap-3 animate-in fade-in zoom-in duration-200">
                    <input
                      autoFocus
                      type="text"
                      value={editNameValue}
                      onChange={(e) => setEditNameValue(e.target.value)}
                      onKeyDown={(e) => {
                        if (e.key === 'Enter') savePlayerName();
                        if (e.key === 'Escape') cancelEditingName();
                      }}
                      className="w-full bg-stone-50 border-2 border-amber-400 rounded-xl px-4 py-2 text-2xl font-bold text-center text-stone-900 focus:ring-4 focus:ring-amber-100 outline-none transition-all"
                    />
                    <div className="flex gap-4">
                      <button 
                        onClick={savePlayerName} 
                        className="flex items-center gap-2 px-4 py-2 bg-green-600 text-white rounded-lg font-bold hover:bg-green-700 shadow-md transition-all active:scale-95"
                      >
                        <Check size={18} /> Save
                      </button>
                      <button 
                        onClick={cancelEditingName} 
                        className="flex items-center gap-2 px-4 py-2 bg-stone-200 text-stone-600 rounded-lg font-bold hover:bg-stone-300 transition-all active:scale-95"
                      >
                        <X size={18} /> Cancel
                      </button>
                    </div>
                  </div>
                ) : (
                  <>
                    <p className="text-4xl font-bold text-stone-900 scrabble-font text-center">
                      {currentPlayer?.name}
                    </p>
                    <button 
                      onClick={() => startEditingName(currentPlayer)}
                      className="mt-2 text-stone-400 hover:text-amber-600 flex items-center gap-1 text-sm font-medium transition-colors"
                    >
                      <Pencil size={14} />
                      Edit Name
                    </button>
                  </>
                )}
              </div>

              <div className="space-y-4">
                <div className="space-y-1">
                  <label className="text-xs font-bold text-stone-500 uppercase tracking-wider">Played Word</label>
                  <input
                    type="text"
                    value={wordInput}
                    onChange={(e) => setWordInput(e.target.value.toUpperCase())}
                    onKeyDown={(e) => e.key === 'Enter' && submitWord()}
                    placeholder="ENTER WORD..."
                    className="w-full bg-stone-50 border-2 border-stone-200 rounded-xl px-4 py-3 text-lg font-bold tracking-widest focus:ring-2 focus:ring-amber-500 focus:border-transparent transition-all outline-none"
                  />
                </div>

                <div className="space-y-1">
                  <label className="text-xs font-bold text-stone-500 uppercase tracking-wider">Points</label>
                  <input
                    type="number"
                    value={pointsInput}
                    onChange={(e) => setPointsInput(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && submitWord()}
                    placeholder="Points"
                    className="w-full bg-stone-50 border-2 border-stone-200 rounded-xl px-4 py-3 text-xl font-bold focus:ring-2 focus:ring-amber-500 focus:border-transparent transition-all outline-none"
                  />
                </div>

                <div className="flex flex-col gap-3 pt-2">
                  <button
                    onClick={submitWord}
                    disabled={!wordInput || !pointsInput}
                    className="w-full bg-amber-600 hover:bg-amber-500 disabled:bg-stone-200 disabled:text-stone-400 text-white py-4 rounded-xl font-bold text-lg shadow-lg hover:shadow-amber-200/50 transition-all flex items-center justify-center gap-2"
                  >
                    <Send size={20} />
                    Add Score
                  </button>

                  <button
                    onClick={endTurn}
                    className="w-full bg-stone-800 hover:bg-stone-700 text-stone-200 py-4 rounded-xl font-bold text-lg transition-all flex items-center justify-center gap-2 shadow-lg"
                  >
                    <SkipForward size={20} />
                    End Turn
                  </button>
                </div>
              </div>

              {/* AI Insight */}
              {(definition || isLoadingDef) && (
                <div className="mt-6 p-4 bg-stone-50 rounded-xl border border-stone-100 flex gap-3 animate-in fade-in duration-300">
                  <Info className="text-amber-600 shrink-0" size={18} />
                  <div>
                    <h4 className="text-xs font-bold text-stone-400 uppercase tracking-wider mb-1">AI Insight</h4>
                    {isLoadingDef ? (
                      <div className="flex gap-1">
                        <div className="w-1.5 h-1.5 bg-stone-300 rounded-full animate-bounce"></div>
                        <div className="w-1.5 h-1.5 bg-stone-300 rounded-full animate-bounce delay-75"></div>
                        <div className="w-1.5 h-1.5 bg-stone-300 rounded-full animate-bounce delay-150"></div>
                      </div>
                    ) : (
                      <p className="text-sm text-stone-600 italic">"{definition}"</p>
                    )}
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* Player Quick Stats */}
          <div className="space-y-3">
            <h2 className="text-xs font-bold text-stone-500 uppercase tracking-widest px-1">Leaderboard</h2>
            {players.map((p, idx) => (
              <StatsCard
                key={p.id}
                name={p.name}
                stats={getPlayerStats(p)}
                isActive={idx === currentPlayerIndex}
              />
            ))}
          </div>
        </div>

        {/* Right Column: Score Table */}
        <div className="lg:col-span-8 bg-white rounded-2xl shadow-sm border border-stone-200 overflow-hidden flex flex-col">
          <div className="bg-stone-50 p-4 border-b border-stone-200 flex justify-between items-center">
            <h2 className="font-bold text-stone-800">Score Sheet</h2>
            <div className="flex gap-2">
               <span className="w-3 h-3 rounded-full bg-red-400"></span>
               <span className="w-3 h-3 rounded-full bg-amber-400"></span>
               <span className="w-3 h-3 rounded-full bg-green-400"></span>
            </div>
          </div>

          <div className="overflow-x-auto flex-grow">
            <table className="w-full text-left border-collapse min-w-[600px]">
              <thead>
                <tr className="bg-stone-50 border-b border-stone-200">
                  <th className="px-6 py-4 text-xs font-bold text-stone-400 uppercase tracking-widest w-16">Rd</th>
                  {players.map((p, idx) => (
                    <th key={p.id} className={`px-6 py-4 relative group ${idx === currentPlayerIndex ? 'bg-amber-50/50' : ''}`}>
                      <div className="flex items-center justify-between gap-2">
                        <div className="flex items-center gap-2 overflow-hidden">
                          <span className={`font-bold truncate ${idx === currentPlayerIndex ? 'text-amber-700' : 'text-stone-800'}`}>
                            {p.name}
                          </span>
                          {!isGameStarted && (
                            <button 
                              onClick={() => startEditingName(p)}
                              title="Edit name"
                              className="text-stone-300 hover:text-amber-500 transition-colors opacity-0 group-hover:opacity-100"
                            >
                              <Pencil size={14} />
                            </button>
                          )}
                        </div>
                        {!isGameStarted && players.length > 1 && (
                          <button 
                            onClick={() => removePlayer(p.id)}
                            title="Remove player"
                            className="text-stone-300 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100 shrink-0"
                          >
                            <X size={16} />
                          </button>
                        )}
                      </div>
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody className="divide-y divide-stone-100">
                {/* Always show rows up to the current round */}
