      const newTurns = [...player.turns];

      if (newTurns[roundIdx]) {
        newTurns[roundIdx] = {
          ...newTurns[roundIdx],
          word: `${newTurns[roundIdx].word}, ${wordInput.trim().toUpperCase()}`,
          points: newTurns[roundIdx].points + points,
        };
      } else {
        newTurns[roundIdx] = {
          word: wordInput.trim().toUpperCase(),
          points,
          timestamp: Date.now()
        };
      }

      player.turns = newTurns;
      updated[currentPlayerIndex] = player;
      return updated;
    });

    setWordInput('');
    setPointsInput('');
    setDefinition(null);
  }, [wordInput, pointsInput, currentPlayerIndex, gameRound]);

  const endTurn = useCallback(() => {
    const roundIdx = gameRound - 1;

    setPlayers(prev => {
      if (prev[currentPlayerIndex].turns[roundIdx]) return prev;

      const updated = [...prev];
      const player = { ...updated[currentPlayerIndex] };
      const newTurns = [...player.turns];
      newTurns[roundIdx] = { word: '—', points: 0, timestamp: Date.now() };
      player.turns = newTurns;
      updated[currentPlayerIndex] = player;
      return updated;
    });

    if (currentPlayerIndex === players.length - 1) {
      setGameRound(prev => prev + 1);
    }

    setCurrentPlayerIndex(prev => (prev + 1) % players.length);
    setWordInput('');
    setPointsInput('');
    setDefinition(null);
    setEditingPlayerId(null);
  }, [players.length, currentPlayerIndex, gameRound]);

  const getPlayerStats = useCallback((player: Player): PlayerStats => {
    const totalScore = player.turns.reduce((sum, t) => sum + (t?.points || 0), 0);
    const validTurns = player.turns.filter(t => t && t.word !== '—');
    const wordCount = validTurns.length;
    const averagePoints = wordCount > 0 ? totalScore / wordCount : 0;

    const highestRound = player.turns.length > 0 
      ? [...player.turns].filter(t => t).sort((a, b) => b.points - a.points)[0]
      : null;

    return { 
      totalScore, 
      averagePoints, 
      highestWord: highestRound && highestRound.word !== '—' ? highestRound : null, 
      wordCount 
    };
  }, []);

  useEffect(() => {
    const timer = setTimeout(async () => {
      if (wordInput.length >= 3) {
        setIsLoadingDef(true);
        const def = await defineWord(wordInput);
        setDefinition(def);
        setIsLoadingDef(false);
      } else {
        setDefinition(null);
      }
    }, 800);
    return () => clearTimeout(timer);
  }, [wordInput]);

  const currentPlayer = players[currentPlayerIndex];

  return (
    <div className="min-h-screen bg-stone-100 pb-12">
      {/* Header */}
      <header className="bg-stone-900 text-white shadow-2xl py-6 sticky top-0 z-50 border-b-2 border-amber-600/30">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 flex flex-wrap justify-between items-center gap-4">
          <div className="flex items-center gap-4">
            <div className="bg-[#0c1a26] p-1 rounded-xl shadow-[0_0_15px_rgba(245,158,11,0.3)] border border-amber-500/20 overflow-hidden">
              <img 
                src="input_file_0.png" 
                alt="Bit Deserty Logo" 
                className="w-12 h-12 object-contain"
                onError={(e) => {
                  e.currentTarget.style.display = 'none';
                  e.currentTarget.parentElement!.innerHTML = '<div class="w-12 h-12 bg-amber-600 flex items-center justify-center font-bold text-stone-900 text-xs">BIT</div>';
                }}
              />
            </div>
            <div>
              <h1 className="text-3xl font-bold tracking-tight scrabble-font leading-none text-white">Lexi Score</h1>
              <p className="text-[10px] font-bold text-amber-500 uppercase tracking-[0.3em] mt-1 opacity-90">Bit Deserty Studios</p>
            </div>
          </div>

          <div className="flex items-center gap-3">
            <button
              onClick={startNewGame}
              className="flex items-center gap-2 bg-stone-800 hover:bg-stone-700 text-stone-300 px-4 py-2 rounded-lg transition-all border border-stone-700 active:scale-95"
            >
              <RotateCcw size={18} />
              <span className="hidden sm:inline">Reset Game</span>
            </button>
            <button
              disabled={isGameStarted}
              onClick={addPlayer}
              className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-all active:scale-95 ${
                isGameStarted 
                ? 'bg-stone-800 text-stone-600 cursor-not-allowed opacity-50' 
                : 'bg-amber-600 hover:bg-amber-500 text-white shadow-lg shadow-amber-900/20'
              }`}
            >
              <UserPlus size={18} />
              <span className="hidden sm:inline">Add Player</span>
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 mt-8 grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* Left Column: Input & Stats */}
        <div className="lg:col-span-4 space-y-6">
          {/* Active Player Status */}
          <div className="bg-white rounded-2xl shadow-sm border border-stone-200 overflow-hidden">
            <div className="bg-amber-50 p-4 border-b border-amber-100 flex items-center justify-between">
              <h2 className="font-bold text-stone-800 flex items-center gap-2">
                <Users size={18} className="text-amber-600" />
                Current Turn
              </h2>
              <span className="text-xs font-semibold text-amber-700 uppercase tracking-widest bg-amber-200 px-2 py-1 rounded">
                Round {gameRound}
              </span>
            </div>
            <div className="p-6">
              <div className="flex flex-col items-center mb-6 min-h-[100px] justify-center">
                {editingPlayerId === currentPlayer.id ? (
                  <div className="w-full flex flex-col items-center gap-3 animate-in fade-in zoom-in duration-200">
                    <input
                      autoFocus
                      type="text"
                      value={editNameValue}
                      onChange={(e) => setEditNameValue(e.target.value)}
                      onKeyDown={(e) => {
                        if (e.key === 'Enter') savePlayerName();
                        if (e.key === 'Escape') cancelEditingName();
                      }}
                      className="w-full bg-stone-50 border-2 border-amber-400 rounded-xl px-4 py-2 text-2xl font-bold text-center text-stone-900 focus:ring-4 focus:ring-amber-100 outline-none transition-all"
                    />
                    <div className="flex gap-4">
                      <button 
                        onClick={savePlayerName} 
                        className="flex items-center gap-2 px-4 py-2 bg-green-600 text-white rounded-lg font-bold hover:bg-green-700 shadow-md transition-all active:scale-95"
                      >
                        <Check size={18} /> Save
                      </button>
                      <button 
                        onClick={cancelEditingName} 
                        className="flex items-center gap-2 px-4 py-2 bg-stone-200 text-stone-600 rounded-lg font-bold hover:bg-stone-300 transition-all active:scale-95"
                      >
                        <X size={18} /> Cancel
                      </button>
                    </div>
                  </div>
                ) : (
                  <>
                    <p className="text-4xl font-bold text-stone-900 scrabble-font text-center">
                      {currentPlayer?.name}
                    </p>
                    <button 
                      onClick={() => startEditingName(currentPlayer)}
                      className="mt-2 text-stone-400 hover:text-amber-600 flex items-center gap-1 text-sm font-medium transition-colors"
                    >
                      <Pencil size={14} />
                      Edit Name
                    </button>
                  </>
                )}
              </div>

              <div className="space-y-4">
                <div className="space-y-1">
                  <label className="text-xs font-bold text-stone-500 uppercase tracking-wider">Played Word</label>
                  <input
                    type="text"
                    value={wordInput}
                    onChange={(e) => setWordInput(e.target.value.toUpperCase())}
                    onKeyDown={(e) => e.key === 'Enter' && submitWord()}
                    placeholder="ENTER WORD..."
                    className="w-full bg-stone-50 border-2 border-stone-200 rounded-xl px-4 py-3 text-lg font-bold tracking-widest focus:ring-2 focus:ring-amber-500 focus:border-transparent transition-all outline-none"
                  />
                </div>

                <div className="space-y-1">
                  <label className="text-xs font-bold text-stone-500 uppercase tracking-wider">Points</label>
                  <input
                    type="number"
                    value={pointsInput}
                    onChange={(e) => setPointsInput(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && submitWord()}
                    placeholder="Points"
                    className="w-full bg-stone-50 border-2 border-stone-200 rounded-xl px-4 py-3 text-xl font-bold focus:ring-2 focus:ring-amber-500 focus:border-transparent transition-all outline-none"
                  />
                </div>

                <div className="flex flex-col gap-3 pt-2">
                  <button
                    onClick={submitWord}
                    disabled={!wordInput || !pointsInput}
                    className="w-full bg-amber-600 hover:bg-amber-500 disabled:bg-stone-200 disabled:text-stone-400 text-white py-4 rounded-xl font-bold text-lg shadow-lg hover:shadow-amber-200/50 transition-all flex items-center justify-center gap-2"
                  >
                    <Send size={20} />
                    Add Score
                  </button>

                  <button
                    onClick={endTurn}
                    className="w-full bg-stone-800 hover:bg-stone-700 text-stone-200 py-4 rounded-xl font-bold text-lg transition-all flex items-center justify-center gap-2 shadow-lg"
                  >
                    <SkipForward size={20} />
                    End Turn
                  </button>
                </div>
              </div>

              {/* AI Insight */}
              {(definition || isLoadingDef) && (
                <div className="mt-6 p-4 bg-stone-50 rounded-xl border border-stone-100 flex gap-3 animate-in fade-in duration-300">
                  <Info className="text-amber-600 shrink-0" size={18} />
                  <div>
                    <h4 className="text-xs font-bold text-stone-400 uppercase tracking-wider mb-1">AI Insight</h4>
                    {isLoadingDef ? (
                      <div className="flex gap-1">
                        <div className="w-1.5 h-1.5 bg-stone-300 rounded-full animate-bounce"></div>
                        <div className="w-1.5 h-1.5 bg-stone-300 rounded-full animate-bounce delay-75"></div>
                        <div className="w-1.5 h-1.5 bg-stone-300 rounded-full animate-bounce delay-150"></div>
                      </div>
                    ) : (
                      <p className="text-sm text-stone-600 italic">"{definition}"</p>
                    )}
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* Player Quick Stats */}
          <div className="space-y-3">
            <h2 className="text-xs font-bold text-stone-500 uppercase tracking-widest px-1">Leaderboard</h2>
            {players.map((p, idx) => (
              <StatsCard
                key={p.id}
                name={p.name}
                stats={getPlayerStats(p)}
                isActive={idx === currentPlayerIndex}
              />
            ))}
          </div>
        </div>

        {/* Right Column: Score Table */}
        <div className="lg:col-span-8 bg-white rounded-2xl shadow-sm border border-stone-200 overflow-hidden flex flex-col">
          <div className="bg-stone-50 p-4 border-b border-stone-200 flex justify-between items-center">
            <h2 className="font-bold text-stone-800">Score Sheet</h2>
            <div className="flex gap-2">
               <span className="w-3 h-3 rounded-full bg-red-400"></span>
               <span className="w-3 h-3 rounded-full bg-amber-400"></span>
               <span className="w-3 h-3 rounded-full bg-green-400"></span>
            </div>
          </div>

          <div className="overflow-x-auto flex-grow">
            <table className="w-full text-left border-collapse min-w-[600px]">
              <thead>
                <tr className="bg-stone-50 border-b border-stone-200">
                  <th className="px-6 py-4 text-xs font-bold text-stone-400 uppercase tracking-widest w-16">Rd</th>
                  {players.map((p, idx) => (
                    <th key={p.id} className={`px-6 py-4 relative group ${idx === currentPlayerIndex ? 'bg-amber-50/50' : ''}`}>
                      <div className="flex items-center justify-between gap-2">
                        <div className="flex items-center gap-2 overflow-hidden">
                          <span className={`font-bold truncate ${idx === currentPlayerIndex ? 'text-amber-700' : 'text-stone-800'}`}>
                            {p.name}
                          </span>
                          {!isGameStarted && (
                            <button 
                              onClick={() => startEditingName(p)}
                              title="Edit name"
                              className="text-stone-300 hover:text-amber-500 transition-colors opacity-0 group-hover:opacity-100"
                            >
                              <Pencil size={14} />
                            </button>
                          )}
                        </div>
                        {!isGameStarted && players.length > 1 && (
                          <button 
                            onClick={() => removePlayer(p.id)}
                            title="Remove player"
                            className="text-stone-300 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100 shrink-0"
                          >
                            <X size={16} />
                          </button>
                        )}
                      </div>
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody className="divide-y divide-stone-100">
                {Array.from({ length: gameRound }).map((_, roundIdx) => (
                  <tr key={roundIdx} className={`transition-colors ${roundIdx === gameRound - 1 ? 'bg-amber-50/10' : 'hover:bg-stone-50/50'}`}>
                    <td className="px-6 py-4 text-sm font-bold text-stone-400">{roundIdx + 1}</td>
                    {players.map((p, playerIdx) => (
                      <td key={p.id} className={`px-6 py-4 border-l border-stone-50 ${playerIdx === currentPlayerIndex && roundIdx === gameRound - 1 ? 'bg-amber-50/30 ring-inset ring-1 ring-amber-100' : ''}`}>
                        {p.turns[roundIdx] ? (
                          <div className="flex items-start justify-between gap-2">
                            <span className="text-sm font-medium text-stone-700 leading-tight break-words max-w-[120px]">
                              {p.turns[roundIdx].word}
                            </span>
                            <span className="text-xs font-bold bg-stone-100 px-2 py-0.5 rounded text-stone-600 shrink-0">
                              {p.turns[roundIdx].points}
                            </span>
                          </div>
                        ) : (
                          <span className="text-stone-200">—</span>
                        )}
                      </td>
                    ))}
                  </tr>
                ))}

                {!isGameStarted && gameRound === 1 && (
                  <tr>
                    <td colSpan={players.length + 1} className="px-6 py-12 text-center text-stone-400 italic">
                      No words played yet. Start by entering a word for {players[currentPlayerIndex].name}.
                    </td>
                  </tr>
                )}
              </tbody>
              <tfoot className="sticky bottom-0 bg-stone-900 text-white font-bold border-t-4 border-amber-600 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.1)]">
                <tr>
                  <td className="px-6 py-6 text-xs uppercase tracking-widest text-stone-400">Total</td>
                  {players.map((p) => (
                    <td key={p.id} className="px-6 py-6 text-2xl scrabble-font">
                      {p.turns.reduce((sum, t) => sum + (t?.points || 0), 0)}
                    </td>
                  ))}
                </tr>
              </tfoot>
            </table>
          </div>
        </div>
      </main>

      {/* Footer Mobile Stats Toggle */}
      <div className="fixed bottom-4 right-4 lg:hidden">
        <button className="bg-stone-900 text-white p-2 rounded-full shadow-2xl border border-stone-700 flex items-center justify-center">
          <img src="input_file_0.png" alt="Bit Deserty" className="w-8 h-8 object-contain" />
        </button>
      </div>
    </div>
  );
};

export default App;

{
  "name": "Lexi Score - Bit Deserty Studios",
  "description": "A high-performance Scrabble scorekeeping application by Bit Deserty Studios featuring real-time statistics, multi-player support, and AI-powered word definitions.",
  "requestFramePermissions": []
}

import React, { useState, useCallback, useMemo, useEffect } from 'react';
import { RotateCcw, Send, SkipForward, Info, Users, Pencil, Check, X, UserPlus } from 'lucide-react';
import { Player, Turn, PlayerStats } from './types';
import StatsCard from './components/StatsCard';
import { defineWord } from './services/geminiService';

const App: React.FC = () => {
  const [players, setPlayers] = useState<Player[]>([
    { id: '1', name: 'Player 1', turns: [] },
    { id: '2', name: 'Player 2', turns: [] }
  ]);
  const [currentPlayerIndex, setCurrentPlayerIndex] = useState(0);
  const [gameRound, setGameRound] = useState(1);
  const [wordInput, setWordInput] = useState('');
  const [pointsInput, setPointsInput] = useState('');
  const [definition, setDefinition] = useState<string | null>(null);
  const [isLoadingDef, setIsLoadingDef] = useState(false);

  // Name Editing State
  const [editingPlayerId, setEditingPlayerId] = useState<string | null>(null);
  const [editNameValue, setEditNameValue] = useState('');

  const isGameStarted = useMemo(() => 
    players.some(p => p.turns.length > 0),
  [players]);

  const startNewGame = useCallback(() => {
    if (confirm("Reset current game and scores?")) {
      setPlayers(prev => prev.map(p => ({ ...p, turns: [] })));
      setCurrentPlayerIndex(0);
      setGameRound(1);
      setWordInput('');
      setPointsInput('');
      setDefinition(null);
      setEditingPlayerId(null);
    }
  }, []);

  const addPlayer = useCallback(() => {
    if (isGameStarted) return;
    const newId = Math.random().toString(36).substr(2, 9);
    setPlayers(prev => [...prev, { id: newId, name: `Player ${prev.length + 1}`, turns: [] }]);
  }, [players.length, isGameStarted]);

  const removePlayer = useCallback((id: string) => {
    if (isGameStarted || players.length <= 1) return;
    setPlayers(prev => prev.filter(p => p.id !== id));
    setCurrentPlayerIndex(0);
  }, [isGameStarted, players.length]);

  const startEditingName = (player: Player) => {
    setEditingPlayerId(player.id);
    setEditNameValue(player.name);
  };

  const savePlayerName = () => {
    if (!editNameValue.trim() || !editingPlayerId) {
      setEditingPlayerId(null);
      return;
    }
    setPlayers(prev => prev.map(p => 
      p.id === editingPlayerId ? { ...p, name: editNameValue.trim() } : p
    ));
    setEditingPlayerId(null);
  };

  const cancelEditingName = () => {
    setEditingPlayerId(null);
  };

  const submitWord = useCallback(() => {
    const points = parseInt(pointsInput);
    if (!wordInput.trim() || isNaN(points)) return;

    const roundIdx = gameRound - 1;

    setPlayers(prev => {
      const updated = [...prev];
      const player = { ...updated[currentPlayerIndex] };
      const newTurns = [...player.turns];

      if (newTurns[roundIdx]) {
        newTurns[roundIdx] = {
          ...newTurns[roundIdx],
          word: `${newTurns[roundIdx].word}, ${wordInput.trim().toUpperCase()}`,
          points: newTurns[roundIdx].points + points,
        };
      } else {
        newTurns[roundIdx] = {
          word: wordInput.trim().toUpperCase(),
          points,
          timestamp: Date.now()
        };
      }

      player.turns = newTurns;
      updated[currentPlayerIndex] = player;
      return updated;
    });

    setWordInput('');
    setPointsInput('');
    setDefinition(null);
  }, [wordInput, pointsInput, currentPlayerIndex, gameRound]);

  const endTurn = useCallback(() => {
    const roundIdx = gameRound - 1;

    setPlayers(prev => {
      if (prev[currentPlayerIndex].turns[roundIdx]) return prev;

      const updated = [...prev];
      const player = { ...updated[currentPlayerIndex] };
      const newTurns = [...player.turns];
      newTurns[roundIdx] = { word: '—', points: 0, timestamp: Date.now() };
      player.turns = newTurns;
      updated[currentPlayerIndex] = player;
      return updated;
    });

    if (currentPlayerIndex === players.length - 1) {
      setGameRound(prev => prev + 1);
    }

    setCurrentPlayerIndex(prev => (prev + 1) % players.length);
    setWordInput('');
    setPointsInput('');
    setDefinition(null);
    setEditingPlayerId(null);
  }, [players.length, currentPlayerIndex, gameRound]);

  const getPlayerStats = useCallback((player: Player): PlayerStats => {
    const totalScore = player.turns.reduce((sum, t) => sum + (t?.points || 0), 0);
    const validTurns = player.turns.filter(t => t && t.word !== '—');
    const wordCount = validTurns.length;
    const averagePoints = wordCount > 0 ? totalScore / wordCount : 0;

    const highestRound = player.turns.length > 0 
      ? [...player.turns].filter(t => t).sort((a, b) => b.points - a.points)[0]
      : null;

    return { 
      totalScore, 
      averagePoints, 
      highestWord: highestRound && highestRound.word !== '—' ? highestRound : null, 
      wordCount 
    };
  }, []);

  useEffect(() => {
    const timer = setTimeout(async () => {
      if (wordInput.length >= 3) {
        setIsLoadingDef(true);
        const def = await defineWord(wordInput);
        setDefinition(def);
        setIsLoadingDef(false);
      } else {
        setDefinition(null);
      }
    }, 800);
    return () => clearTimeout(timer);
  }, [wordInput]);

  const currentPlayer = players[currentPlayerIndex];

  return (
    <div className="min-h-screen bg-stone-100 pb-12">
      {/* Header */}
      <header className="bg-[#0c1a26] text-white shadow-2xl py-6 sticky top-0 z-50 border-b-4 border-amber-500">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 flex flex-wrap justify-between items-center gap-4">
          <div className="flex items-center gap-5">
            <div className="p-1 rounded-2xl shadow-[0_0_20px_rgba(245,158,11,0.4)] border-2 border-amber-500/30 overflow-hidden bg-[#0c1a26]">
              <img 
                src="input_file_0.png" 
                alt="Bit Deserty Logo" 
                className="w-16 h-16 object-contain"
                onError={(e) => {
                  e.currentTarget.style.display = 'none';
                  e.currentTarget.parentElement!.innerHTML = '<div class="w-16 h-16 bg-amber-600 flex items-center justify-center font-bold text-stone-900 text-sm">BIT</div>';
                }}
              />
            </div>
            <div>
              <h1 className="text-4xl font-bold tracking-tight scrabble-font leading-none text-white drop-shadow-md">Lexi Score</h1>
              <p className="text-xs font-black text-amber-500 uppercase tracking-[0.4em] mt-2 opacity-100">Bit Deserty Studios</p>
            </div>
          </div>

          <div className="flex items-center gap-4">
            <button
              onClick={startNewGame}
              className="flex items-center gap-2 bg-[#1a2e40] hover:bg-[#253d54] text-stone-300 px-5 py-2.5 rounded-xl transition-all border border-stone-700 active:scale-95 font-semibold"
            >
              <RotateCcw size={18} />
              <span className="hidden sm:inline">Reset Game</span>
            </button>
            <button
              disabled={isGameStarted}
              onClick={addPlayer}
              className={`flex items-center gap-2 px-5 py-2.5 rounded-xl transition-all active:scale-95 font-bold ${
                isGameStarted 
                ? 'bg-stone-800 text-stone-600 cursor-not-allowed opacity-50' 
                : 'bg-amber-600 hover:bg-amber-500 text-stone-900 shadow-xl shadow-amber-900/40 border-b-4 border-amber-800'
              }`}
            >
              <UserPlus size={18} />
              <span className="hidden sm:inline">Add Player</span>
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 mt-8 grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* Left Column: Input & Stats */}
        <div className="lg:col-span-4 space-y-6">
          {/* Active Player Status */}
          <div className="bg-white rounded-3xl shadow-lg border border-stone-200 overflow-hidden">
            <div className="bg-amber-50 p-5 border-b border-amber-100 flex items-center justify-between">
              <h2 className="font-bold text-stone-800 flex items-center gap-2">
                <Users size={18} className="text-amber-600" />
                Current Turn
              </h2>
              <span className="text-xs font-black text-amber-700 uppercase tracking-widest bg-amber-200 px-3 py-1.5 rounded-lg shadow-sm">
                Round {gameRound}
              </span>
            </div>
            <div className="p-8">
              <div className="flex flex-col items-center mb-8 min-h-[120px] justify-center">
                {editingPlayerId === currentPlayer.id ? (
                  <div className="w-full flex flex-col items-center gap-3 animate-in fade-in zoom-in duration-200">
                    <input
                      autoFocus
                      type="text"
                      value={editNameValue}
                      onChange={(e) => setEditNameValue(e.target.value)}
                      onKeyDown={(e) => {
                        if (e.key === 'Enter') savePlayerName();
                        if (e.key === 'Escape') cancelEditingName();
                      }}
                      className="w-full bg-stone-50 border-2 border-amber-400 rounded-2xl px-5 py-3 text-3xl font-bold text-center text-stone-900 focus:ring-4 focus:ring-amber-100 outline-none transition-all shadow-inner"
                    />
                    <div className="flex gap-4">
                      <button 
                        onClick={savePlayerName} 
                        className="flex items-center gap-2 px-5 py-2.5 bg-green-600 text-white rounded-xl font-bold hover:bg-green-700 shadow-md transition-all active:scale-95"
                      >
                        <Check size={20} /> Save
                      </button>
                      <button 
                        onClick={cancelEditingName} 
                        className="flex items-center gap-2 px-5 py-2.5 bg-stone-200 text-stone-600 rounded-xl font-bold hover:bg-stone-300 transition-all active:scale-95"
                      >
                        <X size={20} /> Cancel
                      </button>
                    </div>
                  </div>
                ) : (
                  <>
                    <p className="text-5xl font-bold text-stone-900 scrabble-font text-center drop-shadow-sm">
                      {currentPlayer?.name}
                    </p>
                    <button 
                      onClick={() => startEditingName(currentPlayer)}
                      className="mt-3 text-stone-400 hover:text-amber-600 flex items-center gap-1.5 text-sm font-bold transition-colors"
                    >
                      <Pencil size={14} />
                      EDIT NAME
                    </button>
                  </>
                )}
              </div>

              <div className="space-y-6">
                <div className="space-y-2">
                  <label className="text-xs font-black text-stone-500 uppercase tracking-[0.2em] ml-1">Played Word</label>
                  <input
                    type="text"
                    value={wordInput}
                    onChange={(e) => setWordInput(e.target.value.toUpperCase())}
                    onKeyDown={(e) => e.key === 'Enter' && submitWord()}
                    placeholder="ENTER WORD..."
                    className="w-full bg-stone-50 border-2 border-stone-200 rounded-2xl px-5 py-4 text-xl font-bold tracking-widest focus:ring-4 focus:ring-amber-500/20 focus:border-amber-500 transition-all outline-none shadow-inner"
                  />
                </div>

                <div className="space-y-2">
                  <label className="text-xs font-black text-stone-500 uppercase tracking-[0.2em] ml-1">Points</label>
                  <input
                    type="number"
                    value={pointsInput}
                    onChange={(e) => setPointsInput(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && submitWord()}
                    placeholder="Points"
                    className="w-full bg-stone-50 border-2 border-stone-200 rounded-2xl px-5 py-4 text-2xl font-bold focus:ring-4 focus:ring-amber-500/20 focus:border-amber-500 transition-all outline-none shadow-inner"
                  />
                </div>

                <div className="flex flex-col gap-4 pt-4">
                  <button
                    onClick={submitWord}
                    disabled={!wordInput || !pointsInput}
                    className="w-full bg-amber-600 hover:bg-amber-500 disabled:bg-stone-200 disabled:text-stone-400 text-stone-900 py-5 rounded-2xl font-black text-xl shadow-xl shadow-amber-900/20 transition-all flex items-center justify-center gap-2 border-b-4 border-amber-800 active:border-b-0 active:translate-y-1"
                  >
                    <Send size={24} />
                    ADD SCORE
                  </button>

                  <button
                    onClick={endTurn}
                    className="w-full bg-[#0c1a26] hover:bg-[#1a2e40] text-amber-500 py-5 rounded-2xl font-black text-xl transition-all flex items-center justify-center gap-2 shadow-xl border-b-4 border-black active:border-b-0 active:translate-y-1"
                  >
                    <SkipForward size={24} />
                    END TURN
                  </button>
                </div>
              </div>

              {/* AI Insight */}
              {(definition || isLoadingDef) && (
                <div className="mt-8 p-5 bg-stone-50 rounded-2xl border border-amber-200/50 flex gap-4 animate-in slide-in-from-bottom-2 duration-500 shadow-sm">
                  <div className="bg-amber-100 p-2 rounded-lg h-fit shrink-0">
                    <Info className="text-amber-700" size={20} />
                  </div>
                  <div>
                    <h4 className="text-[10px] font-black text-amber-600 uppercase tracking-widest mb-1.5">AI Word Insight</h4>
                    {isLoadingDef ? (
                      <div className="flex gap-1.5 py-1">
                        <div className="w-2 h-2 bg-amber-400 rounded-full animate-bounce"></div>
                        <div className="w-2 h-2 bg-amber-400 rounded-full animate-bounce delay-100"></div>
                        <div className="w-2 h-2 bg-amber-400 rounded-full animate-bounce delay-200"></div>
                      </div>
                    ) : (
                      <p className="text-sm text-stone-700 italic leading-relaxed">"{definition}"</p>
                    )}
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* Player Quick Stats */}
          <div className="space-y-4">
            <h2 className="text-xs font-black text-stone-500 uppercase tracking-[0.3em] px-2">Leaderboard</h2>
            {players.map((p, idx) => (
              <StatsCard
                key={p.id}
                name={p.name}
                stats={getPlayerStats(p)}
                isActive={idx === currentPlayerIndex}
              />
            ))}
          </div>
        </div>

        {/* Right Column: Score Table */}
        <div className="lg:col-span-8 bg-white rounded-3xl shadow-xl border border-stone-200 overflow-hidden flex flex-col">
          <div className="bg-[#0c1a26] p-5 border-b border-amber-500/30 flex justify-between items-center">
            <h2 className="font-bold text-white flex items-center gap-3">
              <img src="input_file_0.png" className="w-6 h-6 object-contain" alt="" />
              Score Sheet
            </h2>
            <div className="flex gap-2.5">
               <span className="w-3.5 h-3.5 rounded-full bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.5)]"></span>
               <span className="w-3.5 h-3.5 rounded-full bg-amber-500 shadow-[0_0_8px_rgba(245,158,11,0.5)]"></span>
               <span className="w-3.5 h-3.5 rounded-full bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.5)]"></span>
            </div>
          </div>

          <div className="overflow-x-auto flex-grow custom-scrollbar">
            <table className="w-full text-left border-collapse min-w-[700px]">
              <thead>
                <tr className="bg-stone-50 border-b border-stone-200">
                  <th className="px-8 py-5 text-xs font-black text-stone-400 uppercase tracking-[0.2em] w-20">Rd</th>
                  {players.map((p, idx) => (
                    <th key={p.id} className={`px-8 py-5 relative group ${idx === currentPlayerIndex ? 'bg-amber-50/50' : ''}`}>
                      <div className="flex items-center justify-between gap-3">
                        <div className="flex items-center gap-3 overflow-hidden">
                          <span className={`font-black text-lg tracking-tight truncate ${idx === currentPlayerIndex ? 'text-amber-700' : 'text-stone-800'}`}>
                            {p.name}
                          </span>
                          {!isGameStarted && (
                            <button 
                              onClick={() => startEditingName(p)}
                              title="Edit name"
                              className="text-stone-300 hover:text-amber-500 transition-colors opacity-0 group-hover:opacity-100"
                            >
                              <Pencil size={16} />
                            </button>
                          )}
                        </div>
                        {!isGameStarted && players.length > 1 && (
                          <button 
                            onClick={() => removePlayer(p.id)}
                            title="Remove player"
                            className="text-stone-300 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100 shrink-0"
                          >
                            <X size={18} />
                          </button>
                        )}
                      </div>
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody className="divide-y divide-stone-100">
                {Array.from({ length: Math.max(gameRound, 1) }).map((_, roundIdx) => (
                  <tr key={roundIdx} className={`transition-all duration-300 ${roundIdx === gameRound - 1 ? 'bg-amber-50/10' : 'hover:bg-stone-50/50'}`}>
                    <td className="px-8 py-5 text-sm font-black text-stone-400">{roundIdx + 1}</td>
                    {players.map((p, playerIdx) => (
                      <td key={p.id} className={`px-8 py-5 border-l border-stone-50/50 ${playerIdx === currentPlayerIndex && roundIdx === gameRound - 1 ? 'bg-amber-100/20 ring-inset ring-2 ring-amber-500/20' : ''}`}>
                        {p.turns[roundIdx] ? (
                          <div className="flex items-start justify-between gap-4">
                            <span className="text-base font-bold text-stone-800 leading-tight break-words max-w-[150px] uppercase tracking-wide">
                              {p.turns[roundIdx].word}
                            </span>
                            <span className="text-sm font-black bg-stone-100 px-3 py-1 rounded-lg text-stone-700 shrink-0 border border-stone-200">
                              {p.turns[roundIdx].points}
                            </span>
                          </div>
                        ) : (
                          <span className="text-stone-200 text-xl font-light opacity-50">—</span>
                        )}
                      </td>
                    ))}
                  </tr>
                ))}

                {!isGameStarted && gameRound === 1 && (
                  <tr>
                    <td colSpan={players.length + 1} className="px-8 py-20 text-center">
                      <div className="flex flex-col items-center gap-4 opacity-40">
                        <img src="input_file_0.png" className="w-16 h-16 grayscale opacity-50" alt="" />
                        <p className="text-stone-500 font-bold tracking-wide italic">
                          No words played yet. Start by entering a word for {players[currentPlayerIndex].name}.
                        </p>
                      </div>
                    </td>
                  </tr>
                )}
              </tbody>
              <tfoot className="sticky bottom-0 bg-[#0c1a26] text-white font-bold border-t-4 border-amber-500 shadow-[0_-8px_15px_rgba(0,0,0,0.3)]">
                <tr>
                  <td className="px-8 py-8 text-[10px] font-black uppercase tracking-[0.3em] text-amber-500">Total Score</td>
                  {players.map((p) => (
                    <td key={p.id} className="px-8 py-8 text-4xl scrabble-font text-white drop-shadow-md">
                      {p.turns.reduce((sum, t) => sum + (t?.points || 0), 0)}
                    </td>
                  ))}
                </tr>
              </tfoot>
            </table>
          </div>
        </div>
      </main>

      {/* Footer Mobile Logo Button */}
      <div className="fixed bottom-6 right-6 lg:hidden">
        <div className="relative group">
          <div className="absolute -inset-1 bg-gradient-to-r from-amber-500 to-orange-600 rounded-full blur opacity-75 group-hover:opacity-100 transition duration-1000 group-hover:duration-200 animate-pulse"></div>
          <button className="relative bg-[#0c1a26] text-white p-3 rounded-full shadow-2xl border-2 border-amber-500/50 flex items-center justify-center">
            <img src="input_file_0.png" alt="Bit Deserty" className="w-10 h-10 object-contain" />
          </button>
        </div>
      </div>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar {
          width: 8px;
          height: 8px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: #f1f1f1;
          border-radius: 10px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #cbd5e1;
          border-radius: 10px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover {
          background: #94a3b8;
        }
      `}</style>
    </div>
  );
};

export default App;
